// // This module selects between two 5-bit inputs, A and B, based on the control signal. When the signal is 1, the output is set to A; when the signal is 0, the output is set to B.
module top_module(A,B,signal,out);input [4:0] A, B;
  input signal;
  output reg [4:0] out;
  always@(A or B or signal)
    out <= (signal == 1'b0 ? A : B);
endmodule
